-- Enrichment marathon batch: Craft.io, Craftable, Crafty Controller, Creatio, Crisp, cronicle, Cronitor, Cronofy

-- в”Ђв”Ђ Craft.io в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Craft.io is an AI-powered, end-to-end product management platform that connects strategy, roadmapping, prioritization, and delivery for enterprise product teams.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (per-editor seat)$q$, pricing_model),
  starting_price = COALESCE($q$$24/month per editor$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~30 employees$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Craft.io Review 2026: Features, Pricing & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See Craft.io's per-editor pricing, Guru AI features, and roadmapping tools in this deep dive to decide if the platform fits your product team's workflow.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Craft.io is a product management platform founded in 2015 and headquartered in Tel Aviv, Israel, with roughly 30 employees serving product teams across multiple continents. It positions itself as an end-to-end system for connecting product strategy, planning, and execution in a single collaborative workspace, aimed primarily at product managers, product leaders, and CPOs at mid-market and enterprise software companies. Core capabilities include roadmapping (timeline and Kanban-style views), backlog management, feature prioritization frameworks, capacity planning, and stakeholder alignment tools. A distinguishing feature is the 'Guru' layer, which embeds product management best practices directly into the workflow, paired with 'Guru AI,' an AI assistant that surfaces insights, automates repetitive tasks, and helps turn raw data into prioritization decisions. Craft.io also supports OKR management, letting teams link objectives and key results to initiatives, epics, and features, and build OKR-based roadmaps and dashboards. Enterprise customers get portfolio management across multiple products or business units, multi-level OKRs, automation rules, and advanced security controls including SSO, SAML, and audit logs. The platform integrates with common developer and design tools (such as Jira and other issue trackers) for two-way syncing between roadmap items and engineering tickets, plus dependency management to flag cross-team blockers. Pricing is structured around three tiers. Starter costs $24/month per editor billed monthly (or $19/month billed yearly) and includes a single workspace, limited views, and up to five custom fields, aimed at small teams getting started with structured roadmapping. Pro costs $99/month per editor monthly (or $79/month yearly) and unlocks unlimited workspaces, custom fields, dependency management, design-tool integrations, and optional paid add-ons for OKRs, a customer feedback portal, and capacity planning. Enterprise is custom-priced, billed annually, and bundles all Pro features and add-ons with portfolio-level roadmapping, advanced security, a dedicated customer success manager, and 24/7 support. Only 'editors' вЂ” admins and team leads who actively create or edit content вЂ” require a paid seat; contributors and viewers can be added at no additional cost, which differentiates Craft.io's pricing model from strictly per-seat competitors. A 14-day free trial is available on the Starter and Pro tiers with no credit card required. Craft.io is frequently compared to Productboard, Aha!, and Jira Product Discovery in the product management software category, and it markets itself specifically as distinct from note-taking or CMS tools with similar names. Given its per-editor pricing and enterprise security features, Craft.io tends to suit growing and established product organizations that need governance and portfolio visibility rather than solo builders or very early-stage startups.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '78f287c8-68d3-4606-a4ac-c4ef808b1063';

