-- в”Ђв”Ђ Crisp в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Crisp is an AI-powered customer messaging platform that unifies live chat, email, and helpdesk conversations into one shared team inbox.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (per-workspace subscription)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~30 employees$q$, company_size),
  headquarters = COALESCE($q$Nantes, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Crisp Review 2026: Live Chat & Helpdesk Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Crisp unifies live chat, email, and helpdesk conversations into one AI-powered shared inbox; compare its free plan and 2026 pricing tiers here.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Crisp is a customer messaging and support platform founded in 2015 by Baptiste Jamin and Valerian Saliou, headquartered in Nantes, France, with a small distributed team of roughly a few dozen employees. The product started as a website live chat widget and has expanded into a full omnichannel customer support suite that unifies live chat, shared team email inboxes, contact forms, and messaging channels into a single shared inbox, along with AI chatbot automation, a knowledge base builder, and a workflow automation tool. The chat widget itself supports automatic browser-based language detection and is localized in 60-plus languages, with a separate real-time message translation feature (branded LiveTranslate) that can translate conversations between agents and customers in 50-plus languages using a third-party translation API. Crisp's pricing is structured as a freemium, per-workspace subscription model rather than per-agent seat pricing, which differentiates it from many helpdesk competitors. The Free plan supports 2 agent seats and includes the core chat widget, a shared inbox, mobile apps, chat SDKs for web and mobile embedding, contact forms, e-commerce integrations, and push notifications, with no time limit. Paid tiers scale up from there: Mini at $45/month per workspace (4 seats) adds a shared email inbox, canned response shortcuts, chat triggers, private internal notes, a custom email domain, and unlimited data retention; Essentials at $95/month per workspace (10 seats) adds customer data management (a lightweight CRM), a true omnichannel inbox, a workflow automation builder, an omnichannel AI chatbot, a knowledge base, analytics, and routing/assignment rules; and Plus at $295/month per workspace (20-plus seats), marketed as the best-value tier, adds an AI-first support suite, unlimited automated workflows, a full ticketing system, 100-plus integrations, white-labeling, higher rate limits, and advanced analytics. Enterprise pricing is custom and includes dedicated onboarding, personalized SLAs, and team training. Each paid tier also includes a bundled allotment of AI credits (roughly $5 to $75 worth depending on tier, translating to 90 to 1,350 automated AI conversations per month) that power the chatbot and AI-assisted reply features, with additional usage billed beyond the included allotment. All paid plans include a 14-day free trial with full feature access. Crisp is commonly compared to Intercom, Zendesk, Tidio, and Freshdesk, and its main differentiators are its per-workspace (rather than strictly per-agent) pricing, a generous permanent free tier, and a unified inbox that blends live chat, email, and automation without requiring separate add-on products. It is used primarily by small and mid-sized e-commerce businesses, SaaS companies, and support teams that want an affordable, quick-to-deploy alternative to enterprise helpdesk suites.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b1f76735-5538-4701-8d39-11c92919d1d4';

