-- в”Ђв”Ђ Cronofy в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Cronofy is a calendar API and embeddable scheduling platform that syncs Google, Outlook, and Apple calendars for developers and recruiting teams.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (per-active-user and API usage-based)$q$, pricing_model),
  starting_price = COALESCE($q$$15/month per active seat$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$~46 employees$q$, company_size),
  headquarters = COALESCE($q$Nottingham, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cronofy Review 2026: Calendar API & Scheduling Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Cronofy provides a calendar sync API and embeddable scheduling tools for Google, Outlook, and Apple Calendar; compare its 2026 pricing plans here.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cronofy is a calendar synchronization API and scheduling platform founded in 2014 by engineers Adam Bird and Garry Shutler, headquartered in Nottingham, United Kingdom, with additional offices in London and Amsterdam and roughly 46 employees. The company builds infrastructure for developers and product teams who need reliable, real-time calendar connectivity across Google Calendar, Microsoft 365/Outlook, Apple Calendar, and Exchange without building and maintaining that integration layer themselves. Cronofy's product spans two main surfaces: a Scheduler (embeddable scheduling links and widgets for booking meetings, similar in end-user experience to Calendly) and a developer-facing Calendar API/SDK for building fully custom scheduling and availability experiences inside another product, such as an applicant tracking system or telehealth platform. The company reports its infrastructure has been used to schedule hundreds of millions of events and is particularly well known in the HR technology and recruiting space, where it powers interview-scheduling features for applicant tracking systems, alongside customers in healthcare, financial services, and enterprise software. Key capabilities include real-time two-way calendar sync (so busy/free status and new bookings update instantly across a candidate's or employee's actual calendar), availability rule sets, group and round-robin scheduling for panel interviews, browser extensions for Chrome, Edge, Firefox, and Outlook, and native integrations with recruiting and HR tools such as Greenhouse, Lever, SmartRecruiters, Zoom, Zendesk, HubSpot, and Okta. Cronofy's pricing splits into Scheduler plans and API plans, both using a 'pay for active users, not empty seats' dynamic billing model, meaning seats are assigned based on actual monthly usage rather than total provisioned accounts. Scheduler pricing starts with a Team plan at $15 per active seat per month (unlimited calendar connections and bookings, multi-user scheduling, browser extensions), scaling to a Business plan at $799 per month billed annually (covering up to 50 active seats, adding Scheduler API access, custom domain/branding, and recruiting-tool integrations like Greenhouse and SmartRecruiters), with a custom-priced Enterprise tier above that at roughly $2,999/month equivalent for larger deployments. Separately, API-only pricing for developers building custom integrations starts at a Starter tier around $139/month, scaling through Emerging (~$819/month) and Growth (~$2,399/month) tiers based on usage volume, with a custom Strategic tier for the largest integrators. A minimum monthly commitment of $99 applies to standalone use of Cronofy's AI-driven Meeting Agents feature. A free trial is available across the product line. Cronofy is most commonly compared to Calendly, Nylas, and Google/Microsoft's native calendar APIs, with its core differentiator being deep specialization in reliable, real-time, multi-provider calendar sync as developer infrastructure rather than a general-purpose scheduling app alone.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c6e0d85c-8664-4863-9ef9-fd20448bffd6';

