INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Strategic roadmapping$q$, $q$Build timeline and board-style roadmaps that link directly to OKRs and can be filtered for different stakeholder audiences.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Guru AI assistant$q$, $q$An AI layer that surfaces prioritization insights, automates status updates, and applies embedded product management best practices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$OKR management$q$, $q$Connect company and team objectives to initiatives, epics, and features with dedicated OKR dashboards for tracking progress.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Prioritization frameworks$q$, $q$Score and rank backlog items using built-in prioritization models to keep planning decisions consistent and defensible.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Capacity planning$q$, $q$Weigh team capacity against planned work to avoid overcommitting engineering resources during sprint or release planning.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Dependency management$q$, $q$Surface cross-team and cross-feature dependencies before they become delivery blockers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Feedback portal$q$, $q$Collect and triage customer and stakeholder feedback, then link requests back to roadmap items for traceability.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Enterprise security controls$q$, $q$SSO, SAML, and audit logs on the Enterprise plan support governance requirements for larger organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Editor-based pricing means contributors and viewers can be added for free, lowering the cost of company-wide visibility$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$OKR-to-roadmap linkage gives leadership clear traceability from strategy to shipped features$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Guru AI and the embedded best-practices layer help less experienced product managers apply structured frameworks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Strong enterprise security and portfolio management for organizations running multiple products$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Per-editor pricing can get expensive quickly for larger product teams, especially on the Pro tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Several capabilities (OKRs, feedback portal, capacity planning) are gated as paid add-ons rather than included in Pro$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Enterprise pricing is not published, requiring a sales conversation for larger deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Primarily built for structured, enterprise-style product management workflows, which can feel heavy for very small teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Is Craft.io the same as the Craft notes app or Craft CMS?$q$, $q$No. Craft.io is a dedicated product management platform for roadmapping and backlog prioritization. It is unrelated to the macOS/iOS note-taking app 'Craft' and unrelated to the open-source 'Craft CMS' content management system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Does Craft.io offer a free plan?$q$, $q$Craft.io does not offer a permanently free plan, but it provides a 14-day free trial on its Starter and Pro tiers without requiring a credit card.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$How does Craft.io's pricing work?$q$, $q$Craft.io charges per 'editor' seat вЂ” the people who create and modify roadmap content. Contributors and viewers, who only consume or comment on roadmaps, are unlimited and do not require a paid license.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$What is Guru AI?$q$, $q$Guru AI is Craft.io's built-in AI assistant that surfaces prioritization insights, automates routine tasks like status summaries, and applies embedded product management best practices as teams plan and build roadmaps.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Does Craft.io integrate with Jira?$q$, $q$Yes, Craft.io integrates with common engineering issue trackers including Jira, syncing roadmap items with development tickets so product and engineering stay aligned.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Enterprise roadmap alignment$q$, $q$Product leaders use Craft.io to connect company OKRs to individual product roadmaps and give executives a shared, filterable view of priorities.$q$, $q$CPOs and VPs of Product at mid-market and enterprise companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Multi-product portfolio management$q$, $q$Organizations running several products use the Enterprise tier's portfolio roadmaps to compare priorities and resourcing across business units.$q$, $q$Product operations teams at larger software companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Structured backlog prioritization$q$, $q$Product managers apply built-in scoring frameworks and capacity planning to decide what to build next and defend those decisions to stakeholders.$q$, $q$Individual product managers and small product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Starter$q$, $q$$24/month per editor (monthly) or $19/month per editor (yearly)$q$, $q$Monthly or annual$q$, NULL, $q$["Single workspace","Up to 3 views","Up to 5 custom fields","Core roadmapping and backlog management","Dev tool integrations","Guru best-practices access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Pro$q$, $q$$99/month per editor (monthly) or $79/month per editor (yearly)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited workspaces and custom fields","Dependency management","Design tool integrations","LiveShare","Automated progress tracking","Optional OKR, feedback portal, and capacity planning add-ons"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Portfolio management","Multi-level OKRs","Portfolio roadmaps","Automation rules","SSO, SAML, audit logs","Dedicated customer success manager","24/7 support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Craft.io is a product management platform built to connect product strategy, roadmap planning, and day-to-day execution in one workspace. Founded in 2015 and based in Tel Aviv, Israel, the company focuses on giving product managers, product leaders, and executive stakeholders a shared source of truth for what is being built and why.$q$, $q$The platform is organized around roadmaps, a prioritized backlog, and OKRs, with a built-in 'Guru' layer that surfaces product management best practices as teams work, plus a Guru AI assistant that automates repetitive tasks like status summaries and prioritization scoring.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Roadmapping tools let teams build timeline and board-style roadmaps that can be filtered and shared with different stakeholder audiences, from engineering to the executive team.$q$, $q$OKR management connects company or team objectives directly to initiatives, epics, and features, so roadmap decisions can be traced back to strategic goals through dedicated OKR dashboards.$q$, $q$Prioritization and capacity planning tools apply scoring frameworks to the backlog and factor in team capacity, helping avoid overcommitment during planning cycles.$q$, $q$Dependency management flags cross-team or cross-feature blockers before they cause delivery slippage, and integrations with engineering tools like Jira keep roadmap items in sync with development tickets.$q$, $q$Enterprise-tier customers get portfolio management for coordinating multiple products or business units, along with SSO, SAML, and audit logging for governance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Craft.io prices by 'editor' seat rather than by every user: only people who actively create or modify roadmap content need a paid license, while contributors and viewers are unlimited and free.$q$, $q$Starter runs $24/month per editor (monthly) or $19/month per editor (billed yearly) and covers a single workspace with core roadmapping and backlog features. Pro runs $99/month per editor (monthly) or $79/month per editor (yearly) and adds unlimited workspaces, dependency management, and optional paid add-ons for OKRs, a feedback portal, and capacity planning.$q$, $q$Enterprise is custom-priced and billed annually, bundling every add-on with portfolio roadmaps, advanced security, and a dedicated customer success manager. A 14-day free trial is available on the lower tiers without requiring a credit card.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('78f287c8-68d3-4606-a4ac-c4ef808b1063', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Intelligent Ordering$q$, $q$Centralized vendor order management that automatically identifies price discrepancies and tracks purchase history across suppliers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Inventory tracking$q$, $q$Real-time visibility into stock levels and costs, tied to recipes so variance and margin loss can be detected before they hit financial statements.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Recipe costing$q$, $q$Connects theoretical recipe usage to actual purchasing and inventory data to keep food and beverage costs aligned with menu pricing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$AP automation$q$, $q$AI-assisted invoice processing with automatic three-way matching between invoices, purchase orders, and receiving records.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Unified operations dashboard$q$, $q$Combines food cost, labor, and purchasing data into daily, actionable insights for operators and finance teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Multi-location support$q$, $q$Built for operators managing purchasing and inventory across many restaurant, bar, or hotel locations from one system.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Combines purchasing, inventory, and accounts payable in one connected platform instead of separate point tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$AI-assisted invoice matching can meaningfully reduce manual AP workload for multi-location operators$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Reported operator outcomes (reduced COGS, faster inventory counts) are grounded in real deployment data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Modular licensing lets operators start with the modules most relevant to their operation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$No public pricing, so evaluating cost requires a sales conversation and quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$No published free trial or free plan for smaller operators to test the platform$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Best suited to multi-location or growth-stage operators, less compelling for single-unit independents$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$As a specialized hospitality back-office tool, it does not cover POS, scheduling, or front-of-house functions$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$What is Craftable used for?$q$, $q$Craftable is back-office software for restaurants, bars, and hotels that centralizes purchasing, inventory management, recipe costing, and accounts payable invoice processing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Is Craftable the same as Bevager or Foodager?$q$, $q$Yes. Bevager and Foodager were Craftable's original beverage- and food-focused products; they are now offered together under the unified Craftable platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$How much does Craftable cost?$q$, $q$Craftable does not publish pricing. It charges per location on a custom quote basis, with unlimited user seats and modules (ordering, inventory, AP automation, analytics) that can be licensed independently.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Does Craftable offer a free trial?$q$, $q$Craftable does not advertise a public free trial or free plan; pricing and onboarding are handled through a direct sales process.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$What kind of businesses use Craftable?$q$, $q$Craftable is used by full-service and limited-service restaurants, bars, fast-casual concepts, and select- and full-service hotels, with named customers including bartaco, Jim's Steakout, and Kimpton Hotels.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Multi-location inventory control$q$, $q$Restaurant groups use Craftable to standardize inventory counts and recipe costing across locations, catching variance before it erodes margins.$q$, $q$Multi-unit restaurant and bar operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Accounts payable automation$q$, $q$Finance teams use Craftable's AI-assisted invoice matching to reduce manual data entry and speed up vendor payment approvals.$q$, $q$Hospitality finance and accounting teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$Centralized vendor purchasing$q$, $q$Purchasing managers consolidate orders across suppliers and catch price discrepancies before they hit the bottom line.$q$, $q$Procurement and operations managers at hotels and restaurant groups$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Craftable is a back-office management platform for restaurants, bars, and hotels, built to replace spreadsheet-driven purchasing, inventory, and accounts payable processes with a connected, real-time system. Founded in 2015 and headquartered in Farmers Branch, Texas, the company grew out of its original Bevager (beverage) and Foodager (food) products, which are now offered together under the Craftable brand.$q$, $q$The platform targets multi-location hospitality operators вЂ” full- and limited-service restaurants, bars, fast-casual chains, and hotels вЂ” that need centralized visibility into food and beverage costs, vendor spend, and invoice processing across many sites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Intelligent Ordering centralizes purchase orders across vendors, automatically catching price discrepancies and consolidating purchase history so operators can compare supplier pricing over time.$q$, $q$Inventory and recipe management links physical stock counts to standardized recipes and theoretical usage, helping identify variance and margin loss caused by waste, over-pouring, or portioning errors.$q$, $q$AP automation applies AI-assisted invoice processing with automatic three-way matching against purchase orders and receiving records, flagging mismatches and routing invoices for approval.$q$, $q$A unified analytics dashboard blends food cost, labor, and purchasing data with recommendations designed to support daily operational decisions rather than only month-end reporting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Craftable does not publish standard pricing tiers. The company prices per location on a custom quote basis, with unlimited user seats included in each contract.$q$, $q$Each core module вЂ” ordering, inventory, AP automation, and analytics вЂ” can reportedly be licensed independently, letting operators pay only for the pieces of the platform they need rather than a single bundled package.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b5712ae-a2d8-4a37-a333-309ad689655d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Multi-instance server management$q$, $q$Create, launch, stop, and monitor multiple Minecraft server instances independently from a single web dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Java and Bedrock support$q$, $q$Runs any Java-executable Minecraft server distribution (vanilla, Paper, Spigot, Waterfall, modpacks) as well as Bedrock Edition server executables.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Web-based file manager$q$, $q$Browse, edit, and upload server configuration files, plugins, and world data directly through the browser interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Remote console access$q$, $q$Send server commands and view live console output remotely without needing direct terminal or SSH access.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Scheduled automated tasks$q$, $q$Configure recurring scheduled tasks such as automatic backups and server restarts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Docker and UnRAID support$q$, $q$Pre-built Docker images and UnRAID templates simplify containerized or NAS-based deployment.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Argon2 password hashing and SSL support$q$, $q$Secures the web panel with modern password hashing and optional SSL/TLS certificate encryption.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Completely free and open source with no paid tiers or feature restrictions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Supports both Java and Bedrock Minecraft server executables in one panel$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Self-hosted architecture keeps all server data and backups on the operator's own hardware$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Docker and UnRAID support make it easy to fit into existing home-lab or self-hosting setups$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Requires users to provide and maintain their own server or hosting infrastructure; it is not a hosting service itself$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$As a community-maintained open-source project, support relies on documentation and community channels rather than paid customer support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Initial setup (Python environment, Docker, or manual install) requires more technical comfort than a fully managed hosting panel$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$No official native mobile apps beyond the browser-based progressive web app$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Is Crafty Controller free?$q$, $q$Yes, Crafty Controller is completely free and open source under the GNU General Public License v3. It is supported by optional community donations, not subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Does Crafty Controller work with Bedrock Edition servers?$q$, $q$Yes, in addition to any Java-executable Minecraft server (vanilla, Paper, Spigot, Waterfall, and modpacks), Crafty Controller supports Bedrock Edition server executables.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Do I need my own server to use Crafty Controller?$q$, $q$Yes. Crafty Controller is a management panel, not a hosting provider вЂ” you need your own server, VPS, or home hardware to run Minecraft servers, and Crafty provides the web interface to manage them.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$What operating systems does Crafty Controller support?$q$, $q$Crafty Controller runs on Windows, Linux, and macOS, and also offers Docker images and UnRAID templates for containerized deployment.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Is Crafty Controller safe to expose to the internet?$q$, $q$Crafty Controller includes Argon2 password hashing and supports SSL/TLS certificate encryption for the web panel, though as with any self-hosted admin tool, operators should follow standard security practices like firewalling and strong credentials.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Home-lab Minecraft hosting$q$, $q$Self-hosters run Crafty Controller on a home server or NAS via Docker to manage Minecraft servers for friends and family without manual command-line work.$q$, $q$Home-lab hobbyists and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Community server administration$q$, $q$Server admins for larger Minecraft communities use Crafty's player management, scheduled backups, and remote console to operate servers without direct machine access.$q$, $q$Minecraft community and server administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$Multi-server instance management$q$, $q$Operators running several Minecraft server instances (survival, creative, modded) on one machine use Crafty to manage them all from a single dashboard.$q$, $q$Small hosting providers and technical Minecraft server operators$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Crafty Controller is a free, open-source, self-hosted web control panel for running Minecraft servers. Rather than manually starting a server jar file from a terminal, administrators use Crafty's browser-based interface to launch, stop, and monitor one or more Minecraft server instances from any device.$q$, $q$The project is licensed under the GNU General Public License v3, with its source code maintained publicly on GitLab, and it is sustained through voluntary community donations rather than a commercial pricing model.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Crafty Controller supports any Minecraft server that runs from a Java executable file, including vanilla, Paper, Spigot, Waterfall, and modded distributions, as well as Bedrock Edition server executables.$q$, $q$The web interface provides server instance management, player and permission controls, remote console command execution, a built-in file manager for editing configuration and world files, and scheduled automated tasks such as backups.$q$, $q$It runs on Windows, Linux, and macOS, with pre-built Docker images and UnRAID templates for containerized deployments, plus a mobile-friendly progressive web app for monitoring servers on the go.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Crafty Controller is completely free to download, install, and modify, with no paid tiers or subscription plans. As open-source software, users provide and maintain their own server hardware or hosting; Crafty is purely the management layer on top of it.$q$, $q$The project accepts optional donations through Ko-fi and Patreon to support ongoing development, but no financial contribution is required to use any feature of the panel.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27d05620-43c3-4522-a6b6-5ae2a23a50b9', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$No-code process designer$q$, $q$A visual, BPMN-based workflow builder lets non-developers automate and customize business processes without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Creatio.ai agents$q$, $q$Generative and predictive AI features draft content, score leads, summarize interactions, and recommend next-best actions across sales, marketing, and service.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Sales Creatio$q$, $q$Pipeline and opportunity management, forecasting, and sales process automation built on the shared no-code platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Marketing Creatio$q$, $q$Campaign management, lead nurturing, and marketing automation tools that share data and workflows with the CRM.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Service Creatio$q$, $q$Case and ticket management for customer service teams, with automated routing and SLA tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Freedom UI page designer$q$, $q$Drag-and-drop page and application builder for creating custom business apps on top of the Creatio data model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Unified data model$q$, $q$A shared, no-code-configurable data model underpins all CRM modules, keeping customer data consistent across sales, marketing, and service.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Tight integration between CRM functionality and a genuine no-code development platform, not just CRM customization$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Creatio.ai brings AI-assisted lead scoring, content drafting, and recommendations across the whole platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Unlimited tier bundles all CRM modules, simplifying pricing for large deployments$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Long track record (originally founded 2002) with substantial funding and enterprise customer base$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Minimum annual commitment of roughly $10,000 makes it inaccessible for very small teams or solo users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Sales, Marketing, and Service modules are separate paid add-ons on the lower tiers, adding to total cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$No-code process modeling has a learning curve for teams without prior BPM or workflow-automation experience$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Pricing is comparatively complex, with per-user platform fees plus per-module fees depending on tier$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Is Creatio the same company as bpm'online?$q$, $q$Yes. Creatio was originally founded as Terrasoft in 2002, later rebranded its CRM/BPM product as bpm'online, and unified everything under the Creatio name in October 2019.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$How much does Creatio cost?$q$, $q$Creatio's core platform tiers start around $25/user/month (Growth) and scale to roughly $55/user/month (Enterprise) and $85/user/month (Unlimited), with a minimum annual purchase commitment of about $10,000.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Does Creatio require coding?$q$, $q$No. Creatio is built as a no-code platform with a visual process designer and page builder, though it also supports custom development for teams that want to extend it with code.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$What does Creatio.ai do?$q$, $q$Creatio.ai is the platform's built-in AI layer, offering generative and predictive features such as lead scoring, content drafting, interaction summaries, and next-best-action recommendations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Is Creatio suitable for small businesses?$q$, $q$Creatio's roughly $10,000/year minimum commitment and per-module add-on pricing generally make it better suited to mid-market and enterprise organizations rather than very small businesses.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Unified sales and service CRM$q$, $q$Mid-market and enterprise sales and service teams use Creatio's Sales and Service modules on a shared data model for consistent customer records.$q$, $q$Sales operations and customer service leaders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Custom business process automation$q$, $q$Operations teams use the no-code process designer to automate industry-specific workflows, such as loan approvals or insurance claims, without engineering support.$q$, $q$Business operations and process improvement teams in regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$AI-assisted lead management$q$, $q$Marketing and sales teams use Creatio.ai to score leads, draft outreach, and get next-best-action recommendations inside existing CRM workflows.$q$, $q$Marketing and sales teams at mid-market and enterprise companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Growth$q$, $q$~$25/user/month$q$, $q$Annual (minimum ~$10,000/year commitment)$q$, NULL, $q$["Core no-code platform","Standard CRM capabilities","Sales, Marketing, Service modules available as add-ons (~$15/user/month each)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Enterprise$q$, $q$~$55/user/month$q$, $q$Annual (minimum ~$10,000/year commitment)$q$, NULL, $q$["Expanded automation and integration capabilities","Broader security and administration controls","Sales, Marketing, Service modules available as add-ons"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$Unlimited$q$, $q$~$85/user/month$q$, $q$Annual (custom for large scale)$q$, NULL, $q$["Full platform capabilities with no use-case restrictions","Sales, Marketing, and Service modules included at no extra per-user cost","Designed for complex, large-scale automation"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Creatio is a no-code CRM and business process management platform with roots going back to 2002, when the company was founded as Terrasoft. The product line was rebranded to bpm'online and later unified under the Creatio name in 2019. Today the company is headquartered in Boston, Massachusetts, with more than 700 employees across six offices and a presence in around 25 countries.$q$, $q$The platform combines CRM functionality (Sales, Marketing, and Service modules) with a no-code development studio, so organizations can both run standard CRM workflows out of the box and build custom business applications and processes without writing code.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The no-code studio includes a visual, BPMN-based process designer, a data model builder, and Freedom UI page designers, letting non-developers automate and customize business workflows.$q$, $q$Creatio.ai adds generative and predictive AI agents throughout the platform to draft outreach content, score and prioritize leads, summarize customer interactions, and recommend next-best actions.$q$, $q$Sales, Marketing, and Service Creatio modules cover pipeline management, marketing campaign automation, and case/ticket management respectively, all built on the same underlying no-code platform and data model.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Creatio uses per-user, per-month pricing across three core tiers: Growth (around $25/user/month), Enterprise (around $55/user/month), and Unlimited (around $85/user/month), each unlocking progressively broader automation capabilities and fewer usage restrictions.$q$, $q$The Sales, Marketing, and Service Creatio modules are priced as add-ons of roughly $15/user/month each on the Growth and Enterprise tiers, while the Unlimited tier includes all three modules with no additional per-user module fee.$q$, $q$Creatio enforces a minimum annual purchase commitment of approximately $10,000, which effectively positions the platform for mid-market and enterprise buyers rather than very small teams.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f75ddaa-758b-4b98-b9a1-7abb4b581a78', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Shared team inbox$q$, $q$Unifies live chat, email, and other channels into one inbox so support agents never miss a conversation across channels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$AI chatbot and AI replies$q$, $q$An omnichannel AI chatbot and AI-assisted reply drafting, powered by a monthly AI credit allotment included in each paid tier.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$LiveTranslate$q$, $q$Real-time conversation translation between agents and customers across 50-plus languages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Knowledge base$q$, $q$A customer-facing help center builder for self-service articles, included from the Essentials tier up.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Workflow automation builder$q$, $q$Visual automation tool for triggering chat flows, routing rules, and follow-up actions based on customer behavior.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Chat widget and SDKs$q$, $q$Customizable website chat widget plus SDKs for embedding chat into web and mobile apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Customer data management$q$, $q$A lightweight CRM layer for storing and segmenting customer profiles alongside conversation history.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Permanent free plan with real functionality (2 seats, shared inbox, mobile apps) rather than a short trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Per-workspace pricing instead of per-agent seats can be significantly cheaper for larger support teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Combines live chat, email, chatbot, and knowledge base without needing multiple separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Widget supports 60-plus languages with real-time translation for genuinely global support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$AI features are metered by included credits, so heavy chatbot usage can require additional paid usage$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Higher tiers (Essentials, Plus) get expensive quickly for teams that need omnichannel and automation features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Some advanced features like the full ticketing system and white-labeling are reserved for the top Plus tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$As a smaller, France-based company, its integration ecosystem is narrower than large incumbents like Zendesk or Intercom$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Does Crisp have a free plan?$q$, $q$Yes. Crisp's Free plan includes 2 agent seats, the core chat widget, a shared inbox, mobile apps, and e-commerce integrations at no cost, with no time limit.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Is Crisp priced per agent or per workspace?$q$, $q$Crisp is priced per workspace rather than strictly per agent. Each tier includes a set number of agent seats (for example, 10 on Essentials), so adding agents within that limit doesn't increase the price.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$What languages does Crisp's chat widget support?$q$, $q$The Crisp chat widget is localized in 60-plus languages with automatic browser-based language detection, and its LiveTranslate feature can translate live conversations across 50-plus languages.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Who founded Crisp and where is it based?$q$, $q$Crisp was founded in 2015 by Baptiste Jamin and Valerian Saliou and is headquartered in Nantes, France.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Does Crisp offer a free trial on paid plans?$q$, $q$Yes, all of Crisp's paid plans (Mini, Essentials, Plus) include a 14-day free trial with full feature access.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$E-commerce customer support$q$, $q$Online stores use Crisp's chat widget and e-commerce integrations to answer pre-sale questions and support orders in real time.$q$, $q$Small and mid-sized e-commerce businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$SaaS support and onboarding$q$, $q$SaaS companies use Crisp's shared inbox, chatbot, and knowledge base to handle support tickets and guide new users through onboarding.$q$, $q$SaaS support and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Multilingual global support$q$, $q$Support teams serving international customers use Crisp's widget localization and LiveTranslate to communicate across language barriers without hiring multilingual agents.$q$, $q$Global support teams and multinational businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Free$q$, $q$$0$q$, $q$Forever$q$, NULL, $q$["2 agent seats","Website chat widget","Shared inbox","Mobile apps","Chat SDKs","Contact forms","E-commerce integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Mini$q$, $q$$45/month per workspace$q$, $q$Monthly$q$, NULL, $q$["4 agent seats","Shared email inbox","Chat triggers and shortcuts","Private notes","Custom email domain","Unlimited data retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Essentials$q$, $q$$95/month per workspace$q$, $q$Monthly$q$, NULL, $q$["10 agent seats","Customer data management","Omnichannel inbox","Workflow automation builder","AI chatbot","Knowledge base","Analytics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Plus$q$, $q$$295/month per workspace$q$, $q$Monthly$q$, NULL, $q$["20+ agent seats","AI-first support suite","Unlimited automated workflows","Ticketing system","100+ integrations","White labelling","Advanced analytics"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Dedicated onboarding","Personalized SLAs","Enhanced rate limits","Team training"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Crisp is a customer messaging platform founded in 2015 by Baptiste Jamin and Valerian Saliou, headquartered in Nantes, France. What began as a website live chat widget has grown into a full customer support suite combining live chat, shared email, contact forms, AI chatbot automation, and a knowledge base into one shared team inbox.$q$, $q$The platform is built around a per-workspace pricing model rather than per-agent licensing, which lets teams add support agents without linearly increasing their subscription cost, distinguishing it from many competing helpdesk tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core widget offers real-time live chat with automatic browser-language detection and localization in 60-plus languages, plus LiveTranslate, a real-time conversation translation feature covering 50-plus languages.$q$, $q$The shared inbox unifies live chat, email, and other channels for support teams, with private internal notes, canned response shortcuts, and routing and assignment rules to distribute conversations.$q$, $q$AI features include an omnichannel AI chatbot and AI-assisted reply drafting, powered by a monthly AI credit allotment that scales with the pricing tier.$q$, $q$Additional tools include a workflow automation builder, a customer-facing knowledge base, a lightweight CRM for customer data, and a ticketing system on higher tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Crisp offers a permanent Free plan with 2 agent seats and core chat, inbox, and mobile app functionality. Paid plans are priced per workspace rather than per agent: Mini at $45/month (4 seats), Essentials at $95/month (10 seats), and Plus at $295/month (20-plus seats), each unlocking more automation, AI credits, and integrations.$q$, $q$Enterprise pricing is custom and adds dedicated onboarding, personalized SLAs, and team training. All paid plans include a 14-day free trial, and each tier bundles a monthly allotment of AI credits for chatbot and AI-reply features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
