INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1f76735-5538-4701-8d39-11c92919d1d4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Visual job scheduling$q$, $q$Configure recurring jobs through a multi-select time picker for years, months, days, weekdays, hours, and minutes instead of raw cron syntax.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Distributed worker execution$q$, $q$Distribute job execution across any number of worker servers with automatic discovery and load balancing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Automatic failover and retries$q$, $q$Jobs automatically fail over to backup servers and retry on transient failures without manual intervention.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Live log streaming$q$, $q$Real-time log viewer for running jobs, with graphical progress bars and estimated time remaining.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Historical performance graphs$q$, $q$Tracks average CPU and memory usage per job over time to help detect performance regressions early.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$No database required$q$, $q$All job data, schedules, and logs are stored as JSON files on disk, simplifying deployment and backup.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$API keys and webhooks$q$, $q$Authenticate external applications with API keys and trigger custom webhooks on job success, failure, or completion.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Completely free and open source under the MIT license with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$No external database dependency makes deployment and backups straightforward$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Distributed, multi-server job execution with automatic failover goes well beyond plain cron$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Real-time web UI with live logs and historical performance graphs improves visibility over standard cron$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Requires self-hosting and ongoing maintenance since there is no managed/hosted version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$No dedicated commercial support; help comes from documentation and community channels$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Less suited to complex, dependency-graph-based workflows compared to dedicated orchestration tools like Airflow$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Smaller ecosystem and integration library than commercial scheduling and monitoring platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Is Cronicle free to use?$q$, $q$Yes. Cronicle is fully free and open source under the MIT license, with no paid tiers or subscription required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Does Cronicle need a database?$q$, $q$No. Cronicle stores all job definitions, schedules, and logs as JSON files on disk, so no external database server is required to run it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Can Cronicle run jobs across multiple servers?$q$, $q$Yes. Cronicle supports distributing jobs across any number of worker servers, with automatic discovery of nearby nodes and automatic failover to backups.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Who maintains Cronicle?$q$, $q$Cronicle was created by developer Joseph Huckaby and is maintained as an open-source project on GitHub, with contributions from the community.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$How is Cronicle different from regular cron?$q$, $q$Unlike plain Unix cron, Cronicle adds a web-based UI, visual scheduling, multi-server job distribution with failover, live log streaming, and historical performance tracking.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Self-hosted cron replacement$q$, $q$DevOps teams replace scattered crontab entries across servers with a single Cronicle instance offering a web UI and centralized job history.$q$, $q$DevOps and infrastructure engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Distributed batch job execution$q$, $q$Teams use Cronicle to distribute recurring batch jobs (backups, reports, data syncs) across multiple worker servers with automatic failover.$q$, $q$Engineering teams running scheduled batch workloads$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$Job monitoring and history$q$, $q$Teams rely on Cronicle's live logs and historical CPU/memory graphs to debug failed jobs and catch performance regressions before they cause outages.$q$, $q$Site reliability and platform engineering teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cronicle is a free, open-source task scheduler and job runner created by developer Joseph Huckaby and released under the MIT license. Written in Node.js, it acts as a modern replacement for traditional Unix cron, adding a web-based dashboard, distributed job execution, and real-time monitoring.$q$, $q$The project requires no external database вЂ” job definitions, schedules, and logs are stored as JSON files on disk вЂ” which keeps deployment and backups simple compared to schedulers that depend on a separate database server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cronicle handles scheduled recurring jobs, one-time on-demand jobs, and event-driven jobs, with schedules configured through a visual multi-select time picker rather than raw cron syntax.$q$, $q$Jobs can be distributed across any number of worker servers, with automatic discovery of nearby nodes, automatic failover to backup servers, and automatic retries for transient failures.$q$, $q$The web dashboard provides live log streaming, graphical progress bars with estimated completion times, and historical CPU and memory usage graphs for each job.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cronicle is completely free and open source under the MIT license, with no paid tiers, vendor, or subscription of any kind. Users self-host it on their own servers or infrastructure and are responsible for their own hosting costs.$q$, $q$There is no commercial company behind Cronicle; it is a community-maintained project accepting contributions through its public GitHub repository.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d9fe50ed-7854-4eab-b7e5-09d6879e58b8', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Cron job monitoring$q$, $q$Tracks execution status, duration, and output of cron jobs and scheduled scripts, alerting on failures, timeouts, or missed runs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Heartbeat monitoring$q$, $q$Lets any process or background job check in on an expected schedule, flagging when a check-in is missed.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Uptime monitoring$q$, $q$Regularly checks websites and APIs and alerts the team on downtime or degraded performance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Multi-channel alerting$q$, $q$Sends alerts via email, Slack, SMS, PagerDuty, Opsgenie, and Splunk depending on plan tier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Status pages$q$, $q$Basic status pages on the free plan, with branded and private status page options available on paid plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Data retention and reporting$q$, $q$12 months of monitoring data retention with automated email reports on the Business plan.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Purpose-built for cron and scheduled-job monitoring, catching failure modes like jobs that never start$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Generous free Hacker plan with 5 monitors and Slack/email alerting at no cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Transparent, pay-as-you-go pricing per monitor rather than opaque bundled tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Trusted by large organizations (Johnson & Johnson, Reddit, Square, monday.com) despite being a small team$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Small team size may mean slower feature velocity compared to larger, venture-funded monitoring platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Per-monitor and per-user pricing can add up quickly for teams monitoring many jobs and services$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Premium integrations (PagerDuty, Opsgenie, Splunk) and SMS alerts require the paid Business tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Enterprise pricing starting at $6,000/year is a significant jump from the self-serve Business plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$What does Cronitor monitor?$q$, $q$Cronitor monitors cron jobs and scheduled tasks, website and API uptime, and heartbeat/check-in signals from any recurring process, alerting teams when something fails, runs too long, or never starts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Does Cronitor have a free plan?$q$, $q$Yes, Cronitor's free Hacker plan includes 5 monitors with email and Slack alerting and a basic status page, with no time limit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$How is Cronitor priced?$q$, $q$Cronitor's Business plan is pay-as-you-go at $2 per monitor per month plus $5 per user per month. Enterprise plans start from roughly $6,000 per year with custom limits and a dedicated engineer.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Who founded Cronitor?$q$, $q$Cronitor was founded in March 2014 by Shane Harter, and the company is headquartered in Berkeley, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Does Cronitor support SMS or PagerDuty alerts?$q$, $q$SMS alerts and premium integrations like PagerDuty, Opsgenie, and Splunk are included on the paid Business plan; the free Hacker plan is limited to email and Slack alerts.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Cron job failure detection$q$, $q$Engineering teams monitor critical cron jobs and background tasks so they're alerted immediately if a job fails or silently stops running.$q$, $q$Backend and DevOps engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Website and API uptime tracking$q$, $q$Teams monitor production websites and APIs for downtime or slow response times, with status pages to keep stakeholders informed during incidents.$q$, $q$Site reliability engineers and infrastructure teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Heartbeat monitoring for data pipelines$q$, $q$Data engineering teams use heartbeat checks to confirm that ETL jobs and data pipelines are running on schedule.$q$, $q$Data engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Hacker$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["5 monitors","Email and Slack alerts","Basic status page","50 status page subscribers"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Business$q$, $q$$2/monitor/month + $5/user/month$q$, $q$Monthly, pay-as-you-go$q$, NULL, $q$["Unlimited API requests","10 alert integrations","12-month data retention","SMS alerts","Premium integrations (PagerDuty, Opsgenie, Splunk)","500 status page subscribers","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$Enterprise$q$, $q$From $6,000/year$q$, $q$Annual invoice billing$q$, NULL, $q$["Custom monitoring limits","Custom integrations","Dedicated engineer","Priority support","SAML SSO and SCIM included"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cronitor is a developer-focused monitoring platform founded in March 2014 by Shane Harter, headquartered in Berkeley, California. The product grew out of a simple problem: knowing when a cron job or scheduled background task silently fails or never starts, a failure mode traditional logging tools often miss.$q$, $q$Beyond cron job monitoring, Cronitor has expanded to cover website and API uptime monitoring, heartbeat/check-in monitoring for any recurring process, and status pages for communicating incident status publicly or privately.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cron and scheduled-job monitoring captures job status, execution duration, and output, alerting teams via email, Slack, SMS, PagerDuty, Opsgenie, or Splunk when a job fails, runs too long, or never starts.$q$, $q$Uptime monitoring checks websites and APIs on a regular interval and alerts on downtime or degraded response times, while heartbeat monitoring lets any process check in on an expected schedule.$q$, $q$Status pages (basic on the free plan, branded and private options on paid plans) let teams communicate incident status to internal or external stakeholders.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cronitor's free Hacker plan includes 5 monitors, email and Slack alerts, and a basic status page. The Business plan is pay-as-you-go at $2 per monitor per month plus $5 per user per month, adding unlimited API requests, SMS alerts, premium integrations, and 12-month data retention, with a 14-day free trial.$q$, $q$Enterprise plans start from roughly $6,000 per year on flexible invoice billing, adding custom limits, a dedicated engineer, priority support, and SAML SSO/SCIM at no extra cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76ba7a30-adea-4140-9ee6-3e5cd63011ed', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Real-time calendar sync$q$, $q$Two-way synchronization with Google Calendar, Microsoft 365/Outlook, Apple Calendar, and Exchange that updates instantly as events change.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Embeddable Scheduler$q$, $q$Booking links and widgets that let external users schedule meetings directly into a host's connected calendar.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Calendar API and SDKs$q$, $q$Developer-facing APIs for building fully custom scheduling and availability experiences inside another product.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Group and round-robin scheduling$q$, $q$Supports panel interviews and team-based booking by coordinating availability across multiple calendars at once.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Recruiting tool integrations$q$, $q$Native connections to Greenhouse, Lever, SmartRecruiters, and other ATS platforms for interview scheduling workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Browser extensions$q$, $q$Extensions for Chrome, Edge, Firefox, and Outlook that bring scheduling links directly into email and browsing workflows.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Deep specialization in real-time, multi-provider calendar sync rather than a bolt-on feature of a broader product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Strong presence in HR tech and recruiting through integrations with major ATS platforms like Greenhouse and Lever$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Dynamic 'active user' billing avoids paying for provisioned-but-unused seats$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Separate API-only pricing lets pure developer integrators pay based on usage rather than per-seat Scheduler pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Business and Enterprise Scheduler tiers ($799/month and up) are significantly pricier than consumer scheduling tools like Calendly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$API pricing tiers scale quickly with usage volume, which can be hard to predict for growing integrations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$A $99/month minimum commitment applies to standalone use of the Meeting Agents AI feature$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Primarily positioned for B2B and developer use cases, offering less value for individual solo schedulers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$What is Cronofy used for?$q$, $q$Cronofy provides calendar synchronization and scheduling infrastructure, used both directly as an embeddable Scheduler for booking meetings and as a Calendar API for developers building custom scheduling features into their own products.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Which calendars does Cronofy support?$q$, $q$Cronofy connects with Google Calendar, Microsoft 365/Outlook, Apple Calendar, and Exchange, syncing availability and bookings in real time.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$How much does Cronofy cost?$q$, $q$Cronofy's Scheduler plans start at $15 per active seat per month (Team) up to $799/month (Business, annual billing). Separate API-only pricing starts around $139/month for developers building custom integrations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Who founded Cronofy?$q$, $q$Cronofy was founded in 2014 by engineers Adam Bird and Garry Shutler and is headquartered in Nottingham, United Kingdom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Is Cronofy popular for recruiting and interview scheduling?$q$, $q$Yes, Cronofy is widely used in HR technology, with native integrations into applicant tracking systems like Greenhouse, Lever, and SmartRecruiters for coordinating interview scheduling.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Interview scheduling for recruiting teams$q$, $q$Talent acquisition teams use Cronofy's integrations with Greenhouse, Lever, and SmartRecruiters to coordinate panel interviews across multiple interviewer calendars.$q$, $q$Recruiting and talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Embedded scheduling in SaaS products$q$, $q$Developers use Cronofy's Calendar API to build native scheduling and availability features directly into their own product, such as a telehealth or services marketplace app.$q$, $q$Product engineering teams at SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Meeting booking links$q$, $q$Sales and customer success teams use Cronofy's embeddable Scheduler links to let prospects and customers book meetings without back-and-forth emails.$q$, $q$Sales and customer success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Team (Scheduler)$q$, $q$$15/month per active seat$q$, $q$Monthly$q$, NULL, $q$["Unlimited calendar connections","Unlimited event bookings","Multi-user scheduling","Browser extensions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Business (Scheduler)$q$, $q$$799/month (up to 50 active seats)$q$, $q$Annual$q$, NULL, $q$["All Team features","Scheduler API access","Custom domain and branding","Greenhouse and SmartRecruiters integrations","Personalized onboarding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Enterprise (Scheduler)$q$, $q$~$2,999/month$q$, $q$Annual$q$, NULL, $q$["Large-scale deployment support","Advanced security and admin controls","Custom integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Starter (API)$q$, $q$~$139/month$q$, $q$Monthly$q$, NULL, $q$["Calendar API access","Usage-based limits for smaller integrations"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$Strategic (API)$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Highest usage volume","Custom SLAs and support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cronofy is a calendar synchronization API and scheduling platform founded in 2014 by engineers Adam Bird and Garry Shutler, headquartered in Nottingham, UK, with additional offices in London and Amsterdam. It provides the calendar infrastructure that other products build scheduling features on top of, connecting to Google Calendar, Microsoft 365/Outlook, Apple Calendar, and Exchange.$q$, $q$The company serves two audiences: end users who book meetings through Cronofy's embeddable Scheduler links, and developers who integrate Cronofy's Calendar API/SDK directly into their own product, such as an applicant tracking system or telehealth app that needs real-time availability and booking.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Real-time, two-way calendar sync keeps busy/free status and new bookings accurate across a user's actual calendar the moment they change, rather than relying on periodic polling.$q$, $q$Group and round-robin scheduling supports panel interviews and team-based booking, while configurable availability rules let organizations define working hours, buffers, and booking limits.$q$, $q$Native integrations with recruiting and HR tools such as Greenhouse, Lever, SmartRecruiters, Zoom, Zendesk, HubSpot, and Okta make Cronofy especially popular for interview scheduling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e0d85c-8664-4863-9ef9-fd20448bffd6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cronofy's Scheduler plans start at $15 per active seat per month (Team), scaling to $799/month billed annually for Business (up to 50 active seats plus Scheduler API access), with a custom Enterprise tier above that. Billing follows a dynamic 'pay for active users' model based on actual monthly usage rather than provisioned seats.$q$, $q$Separately, API-only pricing for developers starts around $139/month (Starter) and scales through Emerging (~$819/month) and Growth (~$2,399/month) tiers based on usage volume, with a custom Strategic tier for the largest integrators. A free trial is available.$q$]::text[], 2);
